import { ZuploContext, ZuploRequest, ZoneCache } from "@zuplo/runtime";

export default async function (request: ZuploRequest, context: ZuploContext) {
  const cache = new ZoneCache("test-cache", context);
  const cacheKey = request.url;

  const cachedData = await cache.get(cacheKey);

  if (cachedData) {
    return new Response(JSON.stringify(cachedData), {
      status: 200,
      headers: {
        "content-type": "application/json",
        "x-cache": "hit"
      }
    });
  }

  const response = await fetch("https://echo.zuplo.io/");
  const data = await response.json();

  cache.put(cacheKey, data, 60);

  // Test if it's immediately available
  const testGet = await cache.get(cacheKey);
  context.log.info("testGet immediately after put:", testGet ? "found" : "not found");

  return new Response(JSON.stringify(data), {
    status: 200,
    headers: {
      "content-type": "application/json",
      "x-cache": "miss"
    }
  });
